import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";

export default function ProjectPage() {
  const { id } = useParams();

  const [project, setProject] = useState(null);
  const [user, setUser] = useState(null);
  const [following, setFollowing] = useState(false);

  useEffect(() => {
    init();
  }, [id]);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    const currentUser = data.user;

    setUser(currentUser);

    fetchProject();

    if (currentUser) {
      checkFollow(currentUser.id);
    }
  };

  // 🔥 get project
  const fetchProject = async () => {
    const { data } = await supabase
      .from("projects")
      .select("*")
      .eq("id", id)
      .single();

    setProject(data);
  };

  // 🔥 check follow
  const checkFollow = async (userId) => {
    const { data } = await supabase
      .from("project_followers")
      .select("id")
      .eq("user_id", userId)
      .eq("project_id", id);

    setFollowing(data?.length > 0);
  };

  // 🔥 follow / unfollow
  const handleFollow = async () => {
    if (!user) return;

    if (following) {
      await supabase
        .from("project_followers")
        .delete()
        .eq("user_id", user.id)
        .eq("project_id", id);

      setFollowing(false);
    } else {
      await supabase.from("project_followers").insert([
        {
          user_id: user.id,
          project_id: id,
        },
      ]);

      setFollowing(true);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      {project ? (
        <>
          <h2>{project.title}</h2>
          <p>{project.description}</p>

          {/* 🔥 FOLLOW BUTTON */}
          <button
            onClick={handleFollow}
            style={{
              padding: "8px 16px",
              marginTop: "10px",
              cursor: "pointer",
            }}
          >
            {following ? "Unfollow Project" : "Follow Project"}
          </button>
        </>
      ) : (
        <p>Loading...</p>
      )}
    </div>
  );
}
